INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c47bb0bf-4a92-45c2-847a-85f3e34a7fc4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Batch vs Streaming — Choosing the Right Execution Model$escape$,
  $escape$Spark gives you a unified DataFrame API for both modes, but the execution model underneath is fundamentally different. Batch jobs with `spark.read` load a bounded dataset, optimize the full DAG via Catalyst, and maximize throughput — ideal for nightly ETL, backfills, or ML training pipelines where latency is irrelevant. Structured Streaming with `spark.readStream` treats an unbounded source as an infinite table, emitting results per micro-batch or (experimentally) continuously.

The key trade-off is latency vs. throughput. Batch achieves higher throughput because Spark can sort-merge shuffle data globally. Streaming micro-batches cap at the trigger interval — `Trigger.ProcessingTime("1 minute")` — so end-to-end latency is bounded but shuffle scope is limited to each batch window. `Trigger.Once()` bridges both worlds: streaming semantics with a single batch execution, useful for incremental loads without a persistent streaming job.

Checkpointing overhead is streaming-only — Spark writes offsets and state to a checkpoint location on every trigger, which adds I/O cost absent in batch. If your SLA tolerates 15+ minute latency, batch wins on cost and simplicity every time.$escape$,
  $escape$from pyspark.sql import SparkSession
from pyspark.sql.functions import window, count

spark = SparkSession.builder.appName("batch-vs-stream").getOrCreate()

# Batch: bounded read, full Catalyst optimization
batch_df = spark.read.parquet("s3://events/2024/")
batch_df.groupBy("user_id").count().write.parquet("s3://output/batch/")

# Streaming: unbounded, micro-batch per trigger
stream_df = spark.readStream.format("kafka") \
    .option("subscribe", "events") \
    .load()

query = stream_df.groupBy(window("timestamp", "5 minutes"), "user_id") \
    .agg(count("*").alias("event_count")) \
    .writeStream \
    .trigger(processingTime="1 minute") \
    .option("checkpointLocation", "s3://checkpoints/events/") \
    .outputMode("update") \
    .format("delta") \
    .start()$escape$,
  $escape$python$escape$,
