INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ac4af723-4271-4688-a3ed-ab0b86838222',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Structured Streaming — Event Time, Watermarks, and Stateful Ops$escape$,
  $escape$Spark Structured Streaming distinguishes between event time (the timestamp embedded in the event payload) and processing time (when Spark ingests the record). For late-arriving data — common with mobile clients or distributed producers — processing time is meaningless; only event time reflects what actually happened.

`withWatermark("eventTime", "10 minutes")` tells Spark's internal state store how long to hold open a time window before declaring it complete. Once the max observed event time minus the watermark threshold crosses a window boundary, Spark emits the aggregate and purges that window's state. Without a watermark, state grows unboundedly across micro-batches.

Stateful ops like `mapGroupsWithState` and `flatMapGroupsWithState` let you maintain arbitrary per-key state across batches. The `GroupState` API gives explicit control — check timeouts, update accumulators, and decide when to emit downstream. For windowed aggregations, prefer `window()` + `withWatermark()`: Spark's planner can optimize these into RocksDB-backed state stores, bounding memory even under high-cardinality keys.$escape$,
  $escape$from pyspark.sql import SparkSession
from pyspark.sql.functions import window, col

spark = SparkSession.builder.appName("event-time-demo").getOrCreate()

events = (
    spark.readStream
    .format("kafka")
    .option("subscribe", "clicks")
    .load()
    .selectExpr("CAST(value AS STRING) AS data", "timestamp")
)

result = (
    events
    .withWatermark("timestamp", "10 minutes")
    .groupBy(window(col("timestamp"), "5 minutes", "1 minute"))
    .count()
)

result.writeStream.outputMode("update").format("console").start().awaitTermination()$escape$,
  $escape$python$escape$,
