INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '05bec7e3-a2ba-460d-8f0d-0941c5cbf6d8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Pipeline Design — Idempotency, Retry Logic, and Backfill Strategy$escape$,
  $escape$Spark pipelines fail. Design for it upfront. Idempotency means re-running a job for the same partition produces identical output — achieve this by writing to a staging path then atomically renaming, or by using `insertOverwrite` on Hive/Delta partitions rather than append. With Delta Lake, `replaceWhere` scopes overwrites to a predicate, making reruns safe: `df.write.format("delta").option("replaceWhere", "date = '2024-01-15'").mode("overwrite").save(path)`. For retry logic, wrap stage transitions in try/except and checkpoint intermediate DataFrames to HDFS/S3 using `df.write.parquet(checkpointPath)` — on retry, detect the checkpoint and skip upstream recomputation. Avoid relying solely on Spark's internal task retries (`spark.task.maxFailures`); those retry at the task level, not the stage level, so corrupt source data will keep failing. Backfill strategy: parameterize your job on `start_date`/`end_date`, partition your output by date, and drive backfill via a loop in your orchestrator (Airflow, Dagster). Never hardcode dates inside the Spark job itself. Use `spark.read.option("basePath", root).parquet(f"{root}/date={dt}")` to read specific partitions efficiently without full scans.$escape$,
  $escape$from delta.tables import DeltaTable

def run_pipeline(spark, processing_date: str, output_path: str):
    checkpoint = f"{output_path}/_checkpoint/{processing_date}"

    # Skip recomputation if checkpoint exists
    if DeltaTable.isDeltaTable(spark, checkpoint):
        df = spark.read.format("delta").load(checkpoint)
    else:
        df = spark.read.parquet(f"s3://raw/date={processing_date}")
        df = df.transform(enrich).transform(aggregate)
        df.write.format("delta").mode("overwrite").save(checkpoint)

    # Idempotent write — scoped overwrite, safe to retry
    df.write.format("delta") \
        .option("replaceWhere", f"date = '{processing_date}'") \
        .mode("overwrite") \
        .save(output_path)$escape$,
  $escape$python$escape$,
