INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e307b85e-98f8-4527-90ca-b7fe81b55f5a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Data Partitioning — Pruning, Parallelism, and Processing in Chunks$escape$,
  $escape$Spark processes data in partitions — the fundamental unit of parallelism. Each partition maps to one task on one executor core. Too few partitions starve your cluster; too many cause scheduling overhead. The sweet spot is typically 2–4x your total executor cores.

Partition pruning is Spark's ability to skip irrelevant partitions entirely at the file level. When your DataFrame is backed by Parquet partitioned by `event_date`, a filter like `df.filter(col("event_date") == "2024-01-15")` causes Spark to read only that directory — the Catalyst optimizer pushes the predicate down before any data is loaded. Verify this in the physical plan: look for `PartitionFilters` in the output of `df.explain(true)`.

For wide transformations like `groupBy` or `join`, Spark shuffles data across the network. `spark.sql.shuffle.partitions` (default: 200) controls the post-shuffle partition count — override it per query with `spark.conf.set("spark.sql.shuffle.partitions", "400")`. For large datasets, use `repartition(n, col("user_id"))` to co-locate related rows before a join, avoiding redundant shuffles. Use `coalesce(n)` when reducing partitions without a full shuffle.$escape$,
  $escape$from pyspark.sql import SparkSession
from pyspark.sql.functions import col

spark = SparkSession.builder.getOrCreate()

# Override shuffle partitions for this query
spark.conf.set("spark.sql.shuffle.partitions", "400")

df = spark.read.parquet("s3://bucket/events/")

# Partition pruning: Catalyst pushes this filter to file scan
filtered = df.filter(col("event_date") == "2024-01-15")

# Verify pruning in physical plan — look for PartitionFilters
filtered.explain(True)

# Repartition by join key to co-locate data before join
users = spark.read.parquet("s3://bucket/users/")
result = df.repartition(400, col("user_id")).join(users, "user_id")

# Reduce partition count without full shuffle
result.coalesce(50).write.parquet("s3://bucket/output/")$escape$,
  $escape$python$escape$,
