INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '39a056f8-0da7-4f66-9294-b309283e1569',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Structured Streaming — Incremental Processing with Watermarks$escape$,
  $escape$Spark Structured Streaming processes data incrementally by default — each trigger reads only new records from the source offset forward. The engine maintains offset tracking automatically for sources like Kafka, Delta Lake, and file-based streams. The real challenge is stateful aggregations: without bounds, state grows unboundedly across micro-batches.

Watermarking solves this. Call `.withWatermark("event_time", "10 minutes")` on your streaming DataFrame before a groupBy aggregation. Spark uses the watermark to track the max event time seen and drops state for windows older than `max_event_time - threshold`. This caps memory usage and lets the engine finalize late-arriving-data windows and emit results.

For Delta Lake sources, use `readStream` with `.option("readChangeFeed", "true")` on a CDF-enabled table to consume only row-level changes — inserts, updates, deletes — since the last checkpoint. Combined with `checkpointLocation`, Spark resumes exactly from the last committed offset on restart, making incremental pipelines fault-tolerant without manual offset management.$escape$,
  $escape$from pyspark.sql import SparkSession
from pyspark.sql.functions import window, count

spark = SparkSession.builder.appName("IncrementalDemo").getOrCreate()

kafka_df = (
    spark.readStream
    .format("kafka")
    .option("kafka.bootstrap.servers", "broker:9092")
    .option("subscribe", "events")
    .load()
)

agg_df = (
    kafka_df
    .withWatermark("timestamp", "10 minutes")
    .groupBy(window("timestamp", "5 minutes"))
    .agg(count("*").alias("event_count"))
)

(
    agg_df.writeStream
    .outputMode("append")  # only emit finalized windows
    .option("checkpointLocation", "/tmp/checkpoints/events")
    .format("delta")
    .start("/tmp/output/event_counts")
    .awaitTermination()
)$escape$,
  $escape$python$escape$,
