INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2ead654a-30cc-497b-b036-661214808847',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Structured Streaming — Dead Letter Queues and Partial Failure Handling$escape$,
  $escape$Spark Structured Streaming has no built-in dead letter queue (DLQ), so you must implement one explicitly. The pattern: wrap your processing logic in a `try/catch` inside a `mapPartitions` or `flatMap`, emit failed records to a separate sink (Kafka topic, S3 path, or Delta table), and continue processing clean records.

Use `foreachBatch` to split a micro-batch into good and bad DataFrames before writing. This preserves exactly-once semantics on the success path while giving you full visibility into failures. Never silently drop bad records — schema mismatches, null key violations, and deserialization errors all surface here.

For alerting, attach a `StreamingQueryListener` and override `onQueryProgress` to emit custom metrics — record count, batch duration, input rows vs. output rows. Wire those metrics to Prometheus via a `CollectorRegistry` or push them to Grafana via StatsD. Set a Grafana alert if `numInputRows > 0 && numOutputRows == 0` for two consecutive batches — that pattern signals a silent partial failure where data is consumed but nothing is written.$escape$,
  $escape$spark.streams.addListener(new StreamingQueryListener() {
  override def onQueryProgress(event: QueryProgressEvent): Unit = {
    val prog = event.progress
    val inputRows = prog.numInputRows
    val outputRows = prog.sink.numOutputRows
    if (inputRows > 0 && outputRows == 0) {
      alertingClient.fire(s"Silent failure in ${prog.name}: consumed $inputRows, wrote 0")
    }
    metricsRegistry.gauge("spark.stream.input_rows").set(inputRows)
    metricsRegistry.gauge("spark.stream.output_rows").set(outputRows)
  }
  override def onQueryStarted(event: QueryStartedEvent): Unit = ()
  override def onQueryTerminated(event: QueryTerminatedEvent): Unit =
    if (event.exception.isDefined) alertingClient.fire(s"Query terminated: ${event.exception.get}")
})$escape$,
  $escape$kotlin$escape$,
