INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6ab0d743-9ab0-43c6-be57-7921ec98f22a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Testing Pipelines — Unit Testing Transforms and Integration Testing End-to-End$escape$,
  $escape$Testing Spark pipelines requires two distinct strategies. For unit tests, use `SparkSession` in local mode with `master("local[*]")` to validate individual DataFrame transformations in isolation — no cluster needed. Wrap your transform logic in pure functions that accept and return DataFrames, making them trivially testable. Use `chispa`'s `assert_df_equality` (Python) or ScalaTest's `assertSmallDataFrameEquality` for schema-aware row comparison that handles column ordering and nullability correctly.

For integration tests, spin up a real pipeline end-to-end against a small fixture dataset written to a temp path using `spark.createDataFrame(...).write.parquet(tmp_path)`. Validate output schema with `df.schema == expectedSchema`, check row counts, and spot-check aggregations. Use `@pytest.fixture(scope="session")` to share one `SparkSession` across the test suite — creating a session per test adds 10–30 seconds of JVM startup overhead. Run integration tests with a Spark config that disables shuffle partitions: `spark.conf.set("spark.sql.shuffle.partitions", "4")` to keep tests fast on small data.$escape$,
  $escape$import pytest
from pyspark.sql import SparkSession
from chispa.dataframe_comparer import assert_df_equality
from my_pipeline.transforms import normalize_events

@pytest.fixture(scope="session")
def spark():
    return (SparkSession.builder
        .master("local[*]")
        .config("spark.sql.shuffle.partitions", "4")
        .getOrCreate())

def test_normalize_events_drops_nulls(spark):
    raw = spark.createDataFrame(
        [(1, "click", None), (2, "view", "home")],
        ["user_id", "event", "page"]
    )
    result = normalize_events(raw)
    assert result.count() == 1
    assert "page" in result.columns$escape$,
  $escape$python$escape$,
