INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0a75ed2e-9d59-4867-bd77-297ff2618a39',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Data Lineage — Tracking Origins with DAGs, explain(), and OpenLineage$escape$,
  $escape$Spark tracks transformation lineage natively through its DAG — every RDD holds a reference to its parent transformations. For DataFrames, `df.explain(mode="extended")` dumps four plan stages: parsed, analyzed, optimized, and physical. The analyzed plan is where column-level provenance lives — each output column maps to an `AttributeReference` tied back to its source relation.

For RDD pipelines, `rdd.toDebugString()` prints the full dependency tree with shuffle boundaries marked by indentation depth.

For production lineage, the OpenLineage Spark listener is the practical choice. Configure it via `spark.extraListeners` — no code changes to your jobs required. On every Spark action, it emits structured events (input datasets, output datasets, schema, job metadata) to a compatible backend like Marquez or DataHub.

Impact analysis becomes tractable once lineage is captured: query upstream/downstream graphs to identify all jobs reading a column before a schema change ships. Column-level lineage beyond `explain()` requires parsing `qe.analyzed().output()` inside a `QueryExecutionListener.onSuccess()` callback, or using the `spark-extension` library to extract `ColumnLineage` nodes directly from the logical plan.$escape$,
  $escape$from pyspark.sql import SparkSession

spark = SparkSession.builder \
    .appName("etl-pipeline") \
    .config("spark.extraListeners",
            "io.openlineage.spark.agent.OpenLineageSparkListener") \
    .config("spark.openlineage.transport.type", "http") \
    .config("spark.openlineage.transport.url", "http://marquez:5000") \
    .config("spark.openlineage.namespace", "data-platform") \
    .getOrCreate()

df = spark.read.parquet("s3://warehouse/sales/") \
           .filter("amount > 100") \
           .join(spark.read.parquet("s3://warehouse/customers/"), "customer_id")

df.explain(mode="extended")  # parsed → analyzed → optimized → physical$escape$,
  $escape$python$escape$,
