INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4111c631-77da-49fe-a20e-37622d164042',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Pipeline SLAs — Monitoring Data Freshness with Structured Streaming Metrics$escape$,
  $escape$Spark Structured Streaming exposes a rich set of built-in metrics through `StreamingQueryListener` that most teams underuse. Attach a listener to your `SparkSession` to capture `onQueryProgress` events — each fires after every micro-batch and contains `inputRowsPerSecond`, `processedRowsPerSecond`, `durationMs` (per stage), and crucially `sources[].endOffset` with event-time watermarks.

For data freshness SLAs, compare `sources[].description` event-time against wall-clock time. If your watermark lags by more than your SLA window (e.g., 15 minutes for near-real-time pipelines), emit an alert. Pair this with `queryProgress.batchDuration` to catch micro-batches exceeding your latency budget.

Send metrics to Prometheus via a custom `StreamingQueryListener` that pushes to a Pushgateway, or pipe `queryProgress` JSON to a Delta table for Grafana dashboarding. For batch jobs, use `SparkListener` and track `onJobEnd` stage metrics — `stageInfo.completionTime` minus `submissionTime` gives wall-clock stage SLA compliance directly. Never rely solely on Spark UI; it's ephemeral and not alertable.$escape$,
  $escape$import org.apache.spark.sql.streaming.StreamingQueryListener
import org.apache.spark.sql.streaming.StreamingQueryListener._

val freshnessListener = new StreamingQueryListener {
  override def onQueryProgress(event: QueryProgressEvent): Unit = {
    val progress = event.progress
    val batchDurationMs = progress.durationMs.getOrDefault("triggerExecution", 0L)
    val inputRate = progress.inputRowsPerSecond

    if (batchDurationMs > 60_000L)
      alertSlaBreach(s"Batch exceeded 60s SLA: ${batchDurationMs}ms")

    progress.sources.foreach { source =>
      val lagMs = System.currentTimeMillis() - source.endOffset.toLong
      if (lagMs > 900_000L)
        alertFreshnessViolation(s"Source lag ${lagMs}ms exceeds 15min SLA")
    }
  }
  override def onQueryStarted(event: QueryStartedEvent): Unit = ()
  override def onQueryTerminated(event: QueryTerminatedEvent): Unit = ()
}

spark.streams.addListener(freshnessListener)$escape$,
