INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b41dbef3-bc41-43fd-8c57-11f71cdce48a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Spark Cluster Sizing on Spot Instances — Cut Costs Without Killing Jobs$escape$,
  $escape$Running Spark on spot/preemptible instances can cut costs 60–80%, but naïve configs get you killed mid-stage. The key levers are dynamic allocation, speculation, and checkpointing.

Enable `spark.dynamicAllocation.enabled=true` with `spark.dynamicAllocation.shuffleTracking.enabled=true` — this lets Spark release idle executors without losing shuffle data. Set `spark.dynamicAllocation.executorIdleTimeout=60s` aggressively; unused executors bleed money.

For executor sizing, prefer fewer fat executors over many thin ones on spot: 4 cores / 16 GB each hits the sweet spot — enough parallelism per node while reducing scheduling overhead. Set `spark.executor.memoryOverhead` to at least 10% of heap to prevent OOM kills from JVM metaspace.

Enable `spark.speculation=true` with `spark.speculation.multiplier=1.5` and `spark.speculation.quantile=0.75` — this relaunches stragglers caused by spot preemptions before they stall your whole stage. Pin your driver to an on-demand node via node selectors or Databricks job cluster config. Losing the driver kills the entire job — executors are replaceable, the driver is not.$escape$,
  $escape$spark = SparkSession.builder \
    .config("spark.dynamicAllocation.enabled", "true") \
    .config("spark.dynamicAllocation.shuffleTracking.enabled", "true") \
    .config("spark.dynamicAllocation.minExecutors", "2") \
    .config("spark.dynamicAllocation.maxExecutors", "50") \
    .config("spark.dynamicAllocation.executorIdleTimeout", "60s") \
    .config("spark.executor.cores", "4") \
    .config("spark.executor.memory", "14g") \
    .config("spark.executor.memoryOverhead", "2g") \
    .config("spark.speculation", "true") \
    .config("spark.speculation.multiplier", "1.5") \
    .config("spark.speculation.quantile", "0.75") \
    .getOrCreate()$escape$,
  $escape$python$escape$,
